import React from "react";

function Result({ respuestas }) {
  return (
    <div>
      <h2>📋 Respuestas del Candidato y Evaluación Manual</h2>
      {respuestas.map((r, index) => (
        <div key={index} style={{ borderBottom: "1px solid #ccc", marginBottom: "1rem", paddingBottom: "1rem" }}>
          <p><strong>{r.pregunta}</strong></p>
          <p><strong>Respuesta del postulante:</strong> {r.texto}</p>
          <p><strong>Puntuación del entrevistador (0 a 2):</strong> {r.puntaje_manual}</p>
          <p><strong>Comentario del entrevistador:</strong> {r.comentario_manual || "Sin comentarios."}</p>
        </div>
      ))}
    </div>
  );
}

export default Result;
